[SysClientCacheDataMethodAttribute(true)]
public display container displayHasTextblock()
{
    return FWFTextBlockHelper::hasTextblock(this);
}

    str fwfTextBlockValueAbove()
    {
        FWFTextBlockInstance    instanceTrans;
        FWFTextBlockParm        instanceParm;
        FWFTextBlockValue       value;
        str						textBlock;

        while select RefRecId from instanceTrans
            order by instanceParm.SortOrder
            where instanceTrans.RefRecId   == this.RecId
               && instanceTrans.RefTableId == this.TableId
        join TextBlock from value
            where value.RecId == instanceTrans.ValueRecId
        join SortOrder from instanceParm
            where instanceParm.RecId	== instanceTrans.SetupRecId
               && instanceParm.Position == FWFTextBlockPosition::Above
        {
            if (textBlock)
            {
                textBlock += System.Environment::NewLine;
            }

			textBlock += value.textBlock;
        }

        return textBlock;
    }

str fwfTextBlockValueBelow()
{
    FWFTextBlockInstance    instanceTrans;
    FWFTextBlockParm        instanceParm;
    FWFTextBlockValue       value;
    str						textBlock;

    while select RefRecId from instanceTrans
        order by instanceParm.SortOrder
        where instanceTrans.RefRecId   == this.RecId
           && instanceTrans.RefTableId == this.TableId
    join TextBlock from value
        where value.RecId == instanceTrans.ValueRecId
    join SortOrder from instanceParm
        where instanceParm.RecId	== instanceTrans.SetupRecId
           && instanceParm.Position == FWFTextBlockPosition::Below
    {
        if (textBlock)
        {
            textBlock += System.Environment::NewLine;
        }

        textBlock += value.textBlock;
    }

    return textBlock;
}
